properties.query:
let timeframe = 1h; 
// Isolate Security Log clearing 
let SecurityLogClear = SecurityEvent
    | where TimeGenerated >= ago(timeframe)
    // Filter the EventID before extending variables
    | where EventID == 1102
    | extend Log_Type = "Security Log"
    | project TimeGenerated, HostName = Computer, UserAccount = Account, EventID, Log_Type;
// Isolate System Log clearing 
let SystemLogClear = Event
    | where TimeGenerated >= ago(timeframe)
    // Filter by the EventLog column to reduce query scan time
    | where EventLog == "System" 
    | where EventID == 104
    | extend Log_Type = "System Log"
    | project TimeGenerated, HostName = Computer, UserAccount = UserName, EventID, Log_Type;
// Unify and Handle Errors
union isfuzzy=true SecurityLogClear, SystemLogClear
// Handle empty fields to prevent Sentinel entity mapping failures
| extend UserAccount = iff(isnotempty(UserAccount), UserAccount, "Unknown Account/SYSTEM")
| extend Action_Time = format_datetime(TimeGenerated, 'yyyy-MM-dd HH:mm:ss')
// Auto-generate a URL to jump straight to the Host entity in Sentinel
| extend Host_Investigation_URL = strcat("https://portal.azure.com/#blade/Microsoft_Azure_Security_Insights/EntitySummaryBlade/entityType/Host/entityId/", HostName)
// Project an output
| project Action_Time, HostName, UserAccount, Log_Type, EventID, Host_Investigation_URL
